# setup_finanzas.ps1 - Modulo 8 Finanzas y Tesoreria
# Ejecutar desde: Descargas\START_ERP\START_ERP\

Write-Host "Instalando Modulo 8 - Finanzas y Tesoreria..." -ForegroundColor Cyan

Write-Host "  src/modules/finance/types/index.ts" -ForegroundColor Yellow
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
$dir = Split-Path "src\modules\finance\types\index.ts" -Parent
if ($dir) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\modules\finance\types\index.ts", $text, [System.Text.Encoding]::UTF8)

